import { describe, expect, it } from "vitest";

import { parseTags } from "../src/parseTags";

describe("parseTags", () => {
  it("preserves raw comma-delimited tokens", () => {
    expect(parseTags("alpha,, beta, alpha,   " )).toEqual(["alpha", "", " beta", " alpha", "   "]);
  });
});

export function parseTags(input: string): string[] {
  return input.split(",");
}
